inline const REM *GetREM(const void *buf) {
  return ::flatbuffers::GetRoot<REM>(buf);
}

inline const REM *GetSizePrefixedREM(const void *buf) {
  return ::flatbuffers::GetSizePrefixedRoot<REM>(buf);
}

inline const char *REMIdentifier() {
  return "$REM";
}

inline bool REMBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, REMIdentifier());
}

inline bool SizePrefixedREMBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, REMIdentifier(), true);
}

template <bool B = false>
inline bool VerifyREMBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifyBuffer<REM>(REMIdentifier());
}

template <bool B = false>
inline bool VerifySizePrefixedREMBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifySizePrefixedBuffer<REM>(REMIdentifier());
}

inline void FinishREMBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<REM> root) {
  fbb.Finish(root, REMIdentifier());
}

inline void FinishSizePrefixedREMBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<REM> root) {
  fbb.FinishSizePrefixed(root, REMIdentifier());
}

